  { id: 'capricorn', name: 'Capricorn', title: 'The Eternal Ascent', pantheon: 'Zodiac', align: 'Lawful neutral', hp: 260, AC: 2, MR: 60, divineRank: 'Lesser God', category: 'lesser-gods', domain: 'ambition, endurance, mountains', symbol: 'goat, mountain, spiral', personality: 'Capricorn is what ambition looks like when it has forgotten where the top is. He climbs because stopping would imply there is a ground worth returning to. Even gods feel small near him, as if height itself has become moral.', abilities: ['Summit Strike (Action; 5 ft; +13 to hit; 6d10 bludgeoning; —; prone; 1 round; At will)', 'Summit Pressure (Bonus Action; 20 ft; DC 18 CON; —; —; stunned; 1 round; 3/day)', 'Stone Body (Reaction; Self; —; reduce damage taken by 25; —; —; Instantaneous; 3/day)', 'Ascension Aura (Passive; Self; —; +1 to hit, damage, and AC each round up to +5; —; —; —; —)'], str: '22', dex: '16', con: '22', int: '18', wis: '18', cha: '16' },
  { id: 'aquarius', name: 'Aquarius', title: 'The Thought Stream', pantheon: 'Zodiac', align: 'Neutral good', hp: 190, AC: 0, MR: 55, divineRank: 'Lesser God', category: 'lesser-gods', domain: 'knowledge, water, innovation', symbol: 'water bearer, waves, light', personality: 'Aquarius does not speak in sentences so much as in possibilities. When she looks at a problem, the problem begins to behave differently, as if embarrassed to remain unsolved. Some call her a goddess of invention, others call her a quiet form of revolution.', abilities: ['Idea Manifestation (Action; 60 ft; DC 18 INT; 6d10 force or grant ally +2 to all rolls; —; stunned; 1 round; 3/day)', 'Memory Rewrite (Bonus Action; 30 ft; DC 18 WIS; —; —; incapacitated; 1 round; 3/day)', 'Fluid Defense (Reaction; Self; —; resistance to non-magical damage; —; —; Instantaneous; 3/day)', 'Thought Stream (Passive; 20 ft; —; allies +2 to INT saves; —; —; —; —)'], str: '16', dex: '18', con: '18', int: '22', wis: '20', cha: '18' },
  { id: 'pisces', name: 'Pisces', title: 'The Dreaming Depths', pantheon: 'Zodiac', align: 'Chaotic neutral', hp: 180, AC: 0, MR: 60, divineRank: 'Lesser God', category: 'lesser-gods', domain: 'dreams, illusion, empathy', symbol: 'fish, water, dream', personality: 'Pisces exists in the place where memory stops being reliable. She does not lie; she simply remembers all possibilities at once. Those who stand near her begin to doubt which version of themselves is the original, and she never tells them.', abilities: ['Sleep Dominion (Action; 20 ft; DC 18 WIS; —; —; unconscious; 1 round; 3/day)', 'Dream Projection (Bonus Action; 30 ft; DC 18 WIS; —; —; incapacitated; 1 round; 3/day)', 'Reality Blur (Reaction; Self; —; attacks have disadvantage; —; —; 1 round; 3/day)', 'Emotional Sync (Passive; 30 ft; —; share damage evenly among creatures; —; —; —; —)'], str: '14', dex: '18', con: '16', int: '20', wis: '22', cha: '20' }
